class Solution:
    def countPaths(self, n, edges):
        from collections import deque
        if n <= 1:
            return 0
        is_prime = [True] * (n + 1)
        is_prime[0] = False
        if n >= 1:
            is_prime[1] = False
        for i in range(2, int(n ** 0.5) + 1):
            if is_prime[i]:
                for j in range(i * i, n + 1, i):
                    is_prime[j] = False
        adj = [[] for _ in range(n + 1)]
        for u, v in edges:
            adj[u].append(v)
            adj[v].append(u)
        total = 0
        for a in range(1, n + 1):
            for b in range(a + 1, n + 1):
                parent = {a: None}
                q = deque([a])
                while q:
                    x = q.popleft()
                    if x == b:
                        break
                    for y in adj[x]:
                        if y not in parent:
                            parent[y] = x
                            q.append(y)
                cur = b
                primes_on_path = 0
                while cur is not None:
                    if is_prime[cur]:
                        primes_on_path += 1
                    cur = parent[cur]
                if primes_on_path == 1:
                    total += 1
        return total

