class Solution:
    def countPaths(self, n, edges):
        if n <= 1:
            return 0
        is_prime = [True] * (n + 1)
        is_prime[0] = False
        is_prime[1] = False
        for i in range(2, int(n ** 0.5) + 1):
            if is_prime[i]:
                for j in range(i * i, n + 1, i):
                    is_prime[j] = False
        adj = [[] for _ in range(n + 1)]
        for u, v in edges:
            adj[u].append(v)
            adj[v].append(u)

        comp_id = [-1] * (n + 1)
        comp_size = []
        for start in range(1, n + 1):
            if is_prime[start] or comp_id[start] != -1:
                continue
            cid = len(comp_size)
            size = 0
            stack = [start]
            comp_id[start] = cid
            while stack:
                x = stack.pop()
                size += 1
                for y in adj[x]:
                    if not is_prime[y] and comp_id[y] == -1:
                        comp_id[y] = cid
                        stack.append(y)
            comp_size.append(size)

        ans = 0
        for u in range(1, n + 1):
            if not is_prime[u]:
                continue
            running = 0
            side_total = 0
            for v in adj[u]:
                if is_prime[v]:
                    continue
                size = comp_size[comp_id[v]]
                ans += running * size
                running += size
                side_total += size
            ans += side_total
        return ans

