var countPaths = function(n, edges) {
    if (n <= 1) return 0;
    const isPrime = new Array(n + 1).fill(true);
    isPrime[0] = false;
    isPrime[1] = false;
    for (let i = 2; i * i <= n; i++) {
        if (isPrime[i]) {
            for (let j = i * i; j <= n; j += i) isPrime[j] = false;
        }
    }
    const adj = Array.from({ length: n + 1 }, () => []);
    for (const [u, v] of edges) {
        adj[u].push(v);
        adj[v].push(u);
    }

    const compId = new Array(n + 1).fill(-1);
    const compSize = [];
    for (let start = 1; start <= n; start++) {
        if (isPrime[start] || compId[start] !== -1) continue;
        const cid = compSize.length;
        let size = 0;
        const stack = [start];
        compId[start] = cid;
        while (stack.length) {
            const x = stack.pop();
            size++;
            for (const y of adj[x]) {
                if (!isPrime[y] && compId[y] === -1) {
                    compId[y] = cid;
                    stack.push(y);
                }
            }
        }
        compSize.push(size);
    }

    let ans = 0;
    for (let u = 1; u <= n; u++) {
        if (!isPrime[u]) continue;
        let running = 0;
        let sideTotal = 0;
        for (const v of adj[u]) {
            if (isPrime[v]) continue;
            const size = compSize[compId[v]];
            ans += running * size;
            running += size;
            sideTotal += size;
        }
        ans += sideTotal;
    }
    return ans;
};
